using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Agents.AI;
using OpenAI;

// Configuration
var configuration = new ConfigurationBuilder()
    .AddEnvironmentVariables()
    .Build();

var apiKey = configuration["OPENAI_API_KEY"]
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var modelId = configuration["OPENAI_MODEL"] ?? "gpt-4o-mini-2024-07-18";

// DI setup
var services = new ServiceCollection();

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();

// Tools
var researchTools = new ResearchTools();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// Agent setup using Microsoft Agent Framework
var agent = new ChatClientAgent(chatClient,
    "ResearchAgent",
    """
    You are a research agent. Your job is to research a topic thoroughly by:
    1. Searching the web for relevant information using the SearchWeb tool
    2. Taking notes on key findings using the TakeNote tool
    3. Reviewing your notes with GetNotes when ready to summarize
    4. Providing a comprehensive summary of your findings

    Always search multiple queries to get a well-rounded view of the topic.
    Take notes on the most important facts and insights you discover.
    """)
{
    Tools = tools,
};

// Get the research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Run the agent
var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n--- Research Notes Collected ---");
foreach (var note in researchTools.Notes)
{
    Console.WriteLine($"• {note}");
}

// Tool implementations
public class ResearchTools
{
    private readonly List<string> _notes = [];
    public IReadOnlyList<string> Notes => _notes;

    [Description("Searches the web for information on a query. Returns search results with titles and snippets.")]
    public string SearchWeb([Description("The search query")] string query)
    {
        // Simulated web search results for demonstration.
        // In production, replace with a real search API (e.g., Bing Search API).
        Console.WriteLine($"  [Tool] Searching: \"{query}\"");

        var results = query.ToLowerInvariant() switch
        {
            var q when q.Contains("history") => $"""
                Results for "{query}":
                1. "A Comprehensive History" - Overview covering origins, key milestones, and evolution over time.
                2. "Timeline of Major Events" - Chronological breakdown of pivotal moments and breakthroughs.
                3. "Historical Impact Analysis" - How this topic shaped and was shaped by broader trends.
                """,
            var q when q.Contains("benefit") || q.Contains("advantage") => $"""
                Results for "{query}":
                1. "Key Benefits Explained" - Expert analysis of primary advantages and positive outcomes.
                2. "Research Studies on Effectiveness" - Peer-reviewed evidence supporting claimed benefits.
                3. "Practical Applications" - Real-world examples demonstrating tangible value.
                """,
            var q when q.Contains("challenge") || q.Contains("risk") || q.Contains("concern") => $"""
                Results for "{query}":
                1. "Current Challenges" - Major obstacles and limitations facing the field today.
                2. "Risk Assessment Report" - Identified risks and proposed mitigation strategies.
                3. "Expert Concerns" - Leading voices discuss potential downsides and unknowns.
                """,
            var q when q.Contains("future") || q.Contains("trend") => $"""
                Results for "{query}":
                1. "Future Outlook 2026" - Predictions from industry analysts and researchers.
                2. "Emerging Trends" - New developments poised to reshape the landscape.
                3. "What's Next?" - Upcoming milestones and anticipated breakthroughs.
                """,
            _ => $"""
                Results for "{query}":
                1. "Introduction to {query}" - A comprehensive overview covering fundamentals and key concepts.
                2. "Latest Developments in {query}" - Recent news, studies, and breakthroughs.
                3. "{query}: Expert Perspectives" - Insights from leading researchers and practitioners.
                """
        };

        return results;
    }

    [Description("Takes a note to remember an important finding during research.")]
    public string TakeNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved: \"{note[..Math.Min(note.Length, 60)]}...\"");
        return $"Note saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all notes taken so far during the research session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        Console.WriteLine($"  [Tool] Retrieving {_notes.Count} note(s)");
        return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

